using benchmark_clock = std::chrono::steady_clock;

static const unsigned int base_host_threads =
    (std::thread::hardware_concurrency() == 0 ? 1 : std::thread::hardware_concurrency());

template <typename T>
__global__ void zero_fill_kernel(T* data, size_t n, T value) {
  size_t idx = static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  if (idx < n) data[idx] = value;
}

template <typename T, unsigned int compute_iterations, size_t static_chunk_size>
__global__ void bench_block_kernel(const T* src, T* partial, size_t chunk_count) {
  size_t chunk = static_cast<size_t>(blockIdx.x);
  if (chunk >= chunk_count) return;

  size_t base = chunk * static_chunk_size;
  T local_sum = static_cast<T>(0);

#ifdef BASELINE_IMPL
  T f = src[base + 0];
  for (size_t i = threadIdx.x; i < static_chunk_size; i += blockDim.x) {
    T t = src[base + i];
#pragma unroll
    for (unsigned int j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    local_sum += t;
  }
#else
  T f0 = src[base + 0], f1 = src[base + 1], f2 = src[base + 2], f3 = src[base + 3];
  T f4 = src[base + 4], f5 = src[base + 5], f6 = src[base + 6], f7 = src[base + 7];

  for (size_t i = threadIdx.x; i < static_chunk_size; i += blockDim.x) {
    T v = src[base + i];
    T t0 = v, t1 = v, t2 = v, t3 = v, t4 = v, t5 = v, t6 = v, t7 = v;

#pragma unroll
    for (unsigned int j = 0; j < (compute_iterations / 8); j++) {
      t0 = t0 * t0 + f0;
      t1 = t1 * t1 + f1;
      t2 = t2 * t2 + f2;
      t3 = t3 * t3 + f3;
      t4 = t4 * t4 + f4;
      t5 = t5 * t5 + f5;
      t6 = t6 * t6 + f6;
      t7 = t7 * t7 + f7;
    }
    if (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
    if (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
    if (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
    if (compute_iterations % 8 > 3) t3 = t3 * t3 + f3;
    if (compute_iterations % 8 > 4) t4 = t4 * t4 + f4;
    if (compute_iterations % 8 > 5) t5 = t5 * t5 + f5;
    if (compute_iterations % 8 > 6) t6 = t6 * t6 + f6;

    local_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
  }
#endif

  extern __shared__ unsigned char smem_raw[];
  T* smem = reinterpret_cast<T*>(smem_raw);
  smem[threadIdx.x] = local_sum;
  __syncthreads();

  for (unsigned int s = blockDim.x >> 1; s > 0; s >>= 1) {
    if (threadIdx.x < s) smem[threadIdx.x] += smem[threadIdx.x + s];
    __syncthreads();
  }

  if (threadIdx.x == 0) partial[chunk] = smem[0];
}

template <typename T>
__global__ void reduce_sum_kernel(const T* in, T* out, size_t n) {
  size_t tid = threadIdx.x;
  size_t i = static_cast<size_t>(blockIdx.x) * (blockDim.x * 2) + tid;

  T sum = static_cast<T>(0);
  if (i < n) sum += in[i];
  if (i + blockDim.x < n) sum += in[i + blockDim.x];

  extern __shared__ unsigned char smem_raw[];
  T* smem = reinterpret_cast<T*>(smem_raw);
  smem[tid] = sum;
  __syncthreads();

  for (unsigned int s = blockDim.x >> 1; s > 0; s >>= 1) {
    if (tid < s) smem[tid] += smem[tid + s];
    __syncthreads();
  }

  if (tid == 0) out[blockIdx.x] = smem[0];
}

template <typename T, unsigned int compute_iterations>
class BenchWorkspace {
 public:
  explicit BenchWorkspace(size_t len) {
    static constexpr size_t static_chunk_size = 4096;
    chunk_count_ = len / static_chunk_size;
    if (chunk_count_ == 0) chunk_count_ = 1;
    CUDA_SAFE_CALL(cudaMalloc(&buf1_, chunk_count_ * sizeof(T)));
    CUDA_SAFE_CALL(cudaMalloc(&buf2_, chunk_count_ * sizeof(T)));
  }

  ~BenchWorkspace() {
    if (buf1_) cudaFree(buf1_);
    if (buf2_) cudaFree(buf2_);
  }

  size_t run(size_t len, T* d_src) {
    static constexpr size_t static_chunk_size = 4096;
    const int threads = 256;
    const int blocks = static_cast<int>(len / static_chunk_size);

    bench_block_kernel<T, compute_iterations, static_chunk_size>
        <<<blocks, threads, threads * sizeof(T)>>>(d_src, buf1_, blocks);
    CUDA_SAFE_CALL(cudaGetLastError());

    T* in = buf1_;
    T* out = buf2_;
    size_t n = static_cast<size_t>(blocks);

    while (n > 1) {
      int rblocks = static_cast<int>((n + (threads * 2 - 1)) / (threads * 2));
      reduce_sum_kernel<T><<<rblocks, threads, threads * sizeof(T)>>>(in, out, n);
      CUDA_SAFE_CALL(cudaGetLastError());
      n = static_cast<size_t>(rblocks);
      T* tmp = in;
      in = out;
      out = tmp;
    }

    CUDA_SAFE_CALL(cudaMemcpy(d_src, in, sizeof(T), cudaMemcpyDeviceToDevice));
    return len;
  }

 private:
  T* buf1_{nullptr};
  T* buf2_{nullptr};
  size_t chunk_count_{0};
};

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element /*seed1*/, const Element /*seed2*/, Element* src,
             BenchWorkspace<Element, compute_iterations>& ws) {
  return ws.run(len, src);
}

static long long runbench_warmup(void* dmem, size_t size_bytes) {
  const size_t num_elements = size_bytes / sizeof(double);
  auto timer_start = benchmark_clock::now();

  double* ptr = reinterpret_cast<double*>(dmem);
  BenchWorkspace<double, 16> ws(num_elements);
  bench<double, 16>(num_elements, 1.0, -1.0, ptr, ws);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
static double measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  CUDA_SAFE_CALL(cudaDeviceSynchronize());
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.0;
}

template <typename Op>
static double benchmark_omp(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  double duration = op();
  (void)duration;
  std::vector<double> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  if (base_host_threads > 1) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_(memory_space), compute_iterations_(compute_iterations) {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* dmem, size_t size_bytes) {
  ComputeSpace cs{size_bytes, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(dmem);
  BenchWorkspace<float, compute_iterations> ws_sp(cs.element_count<float>());
  auto kernel_time_mad_sp = benchmark_omp([&] {
    return measure_operation([&] {
      bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, c_as_float, ws_sp);
    });
  });

  double* c_as_double = reinterpret_cast<double*>(dmem);
  BenchWorkspace<double, compute_iterations> ws_dp(cs.element_count<double>());
  auto kernel_time_mad_dp = benchmark_omp([&] {
    return measure_operation([&] {
      bench<double, compute_iterations>(cs.element_count<double>(), 1., -1., c_as_double, ws_dp);
    });
  });

  int* c_as_int = reinterpret_cast<int*>(dmem);
  BenchWorkspace<int, compute_iterations> ws_int(cs.element_count<int>());
  auto kernel_time_mad_int = benchmark_omp([&] {
    return measure_operation([&] {
      bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int, ws_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp * 1000. /
                   (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp * 1000. /
                   (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int * 1000. /
                   static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int * 1000. /
                   (1000. * 1000. * 1000.)
            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* dmem, size_t size_bytes) {
  runbench<compute_iterations>(dmem, size_bytes);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* dmem, size_t size_bytes) {
  runbench_range<j1>(dmem, size_bytes);
  runbench_range<j2, Args...>(dmem, size_bytes);
}

extern "C" void mixbenchGPU(double* c, long size) {
  const size_t size_bytes = static_cast<size_t>(size) * sizeof(double);

  void* dmem = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&dmem, size_bytes));

  size_t int_count = size_bytes / sizeof(int);
  const int threads = 256;
  int blocks = static_cast<int>((int_count + threads - 1) / threads);
  zero_fill_kernel<int><<<blocks, threads>>>(reinterpret_cast<int*>(dmem), int_count, 0);
  CUDA_SAFE_CALL(cudaGetLastError());
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(dmem, size_bytes);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8, 8 * 8,
                 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8, 40 * 8, 64 * 8>(
      dmem, size_bytes);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  if (c != nullptr && size > 0) {
    CUDA_SAFE_CALL(cudaMemcpy(c, dmem, sizeof(double), cudaMemcpyDeviceToHost));
  }

  CUDA_SAFE_CALL(cudaFree(dmem));
}
